class Solution {
public:
    int minimumOneBitOperations(int n) {
        int operations = 0;
        while (n > 0) {
            if (n & 1) {
                n = (n >> 1) | 1;
            } else {
                n >>= 1;
            }
            operations++;
        }
        return operations;
    }
};
